namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    public string Name { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments = new()
    {
        new Department { Id = 1, Name = "Computer Science", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
        new Department { Id = 2, Name = "Mathematics", Description = "Exploration of abstract structures, quantities, and patterns through rigorous logical reasoning." },
        new Department { Id = 3, Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces governing the natural world." },
        new Department { Id = 4, Name = "English Literature", Description = "Critical analysis of literary texts spanning diverse periods, genres, and cultural traditions." },
        new Department { Id = 5, Name = "Biology", Description = "Study of living organisms, their structures, functions, evolution, and interactions with the environment." },
        new Department { Id = 6, Name = "History", Description = "Examination of past events, societies, and civilizations to understand human development and change." }
    };

    private readonly List<Course> _courses = new()
    {
        new Course { Id = 1, Code = "CS101", Name = "Introduction to Programming", Description = "A foundational course covering programming concepts using Python. Topics include variables, control flow, functions, data structures, and object-oriented programming basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has over 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", IsFeatured = true },
        new Course { Id = 2, Code = "CS301", Name = "Data Structures and Algorithms", Description = "Advanced study of data organization and algorithm design. Covers trees, graphs, hash tables, sorting algorithms, dynamic programming, and complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", DepartmentId = 1, InstructorName = "Prof. Michael Torres", InstructorBio = "Prof. Torres specializes in algorithm optimization and has contributed to several open-source projects. He received his doctorate from Stanford University.", IsFeatured = true },
        new Course { Id = 3, Code = "CS420", Name = "Machine Learning", Description = "Introduction to machine learning techniques including supervised and unsupervised learning, neural networks, and deep learning frameworks.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", DepartmentId = 1, InstructorName = "Dr. Aisha Patel", InstructorBio = "Dr. Patel is a researcher in artificial intelligence with publications in top-tier conferences. She previously worked at Google DeepMind.", IsFeatured = false },
        new Course { Id = 4, Code = "MATH201", Name = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 2, InstructorName = "Dr. James Wright", InstructorBio = "Dr. Wright is an accomplished mathematician specializing in abstract algebra. He has authored two widely-used textbooks on linear algebra.", IsFeatured = true },
        new Course { Id = 5, Code = "MATH305", Name = "Differential Equations", Description = "Methods for solving ordinary and partial differential equations with applications in physics and engineering.", Credits = 4, Schedule = "Tue/Thu 1:00–2:15 PM", DepartmentId = 2, InstructorName = "Prof. Elena Volkov", InstructorBio = "Prof. Volkov brings 20 years of research experience in applied mathematics from the Russian Academy of Sciences.", IsFeatured = false },
        new Course { Id = 6, Code = "PHYS101", Name = "General Physics I", Description = "Introduction to classical mechanics including kinematics, Newton's laws, energy, momentum, and rotational motion.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM + Lab Thu 2:00–4:00 PM", DepartmentId = 3, InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an experimental physicist who has worked at CERN and Fermilab before joining academia.", IsFeatured = true },
        new Course { Id = 7, Code = "PHYS310", Name = "Quantum Mechanics", Description = "Foundational principles of quantum theory including wave functions, Schrödinger equation, operators, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", DepartmentId = 3, InstructorName = "Prof. Diana Hartwell", InstructorBio = "Prof. Hartwell is a theoretical physicist with groundbreaking research in quantum information theory.", IsFeatured = false },
        new Course { Id = 8, Code = "ENG110", Name = "Introduction to Literary Analysis", Description = "Develops skills in close reading and critical interpretation of poetry, fiction, and drama from various literary periods.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", DepartmentId = 4, InstructorName = "Dr. Margaret O'Brien", InstructorBio = "Dr. O'Brien is a specialist in Victorian literature and narrative theory with publications in leading literary journals.", IsFeatured = false },
        new Course { Id = 9, Code = "ENG350", Name = "Shakespeare and Early Modern Drama", Description = "In-depth study of Shakespeare's major plays and their theatrical, cultural, and political contexts in early modern England.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", DepartmentId = 4, InstructorName = "Prof. William Ashford", InstructorBio = "Prof. Ashford has directed numerous Shakespeare productions and is a Fellow of the Royal Shakespeare Company.", IsFeatured = false },
        new Course { Id = 10, Code = "BIO101", Name = "Introduction to Biology", Description = "Survey of biological principles including cell biology, genetics, evolution, ecology, and organismal diversity.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Tue 3:00–5:00 PM", DepartmentId = 5, InstructorName = "Dr. Lisa Nakamura", InstructorBio = "Dr. Nakamura is a cell biologist whose research focuses on stem cell differentiation and regenerative medicine.", IsFeatured = true },
        new Course { Id = 11, Code = "BIO405", Name = "Molecular Genetics", Description = "Advanced study of gene structure, expression, regulation, and modern genomic technologies including CRISPR.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", DepartmentId = 5, InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor leads a genetics research lab and has contributed to the Human Genome Project.", IsFeatured = false },
        new Course { Id = 12, Code = "HIST101", Name = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", DepartmentId = 6, InstructorName = "Dr. Catherine Morales", InstructorBio = "Dr. Morales is a historian of the ancient Mediterranean world with fieldwork experience in Greece and Turkey.", IsFeatured = false }
    };

    public List<Department> GetDepartments() => _departments;

    public List<Course> GetCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Name.ToLowerInvariant().Contains(term) ||
                c.Code.ToLowerInvariant().Contains(term));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);
}

