@page "/departments"
@inject CatalogService CatalogService

<PageTitle>Departments</PageTitle>

<h1>Academic Departments</h1>

<div class="course-grid">
    @foreach (var dept in CatalogService.GetDepartments())
    {
        <div class="card">
            <h2>@dept.Name</h2>
            <p>@dept.Description</p>
            <a href="courses?departmentId=@dept.Id">View Courses →</a>
        </div>
    }
</div>

@page "/courses"
@inject CatalogService CatalogService

<PageTitle>Courses</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="search-form">
    <div class="form-row">
        <input type="text" name="search" value="@Search" placeholder="Search by name or code..." />
        <select name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
        <button type="submit">Search</button>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Any())
{
    <div class="course-grid">
        @foreach (var course in courses)
        {
            <div class="card">
                <h3><a href="courses/@course.Id">@course.Code — @course.Name</a></h3>
                <p><strong>Credits:</strong> @course.Credits · <strong>Department:</strong> @CatalogService.GetDepartment(course.DepartmentId)?.Name</p>
                <p>@course.Schedule</p>
            </div>
        }
    </div>
}
else
{
    <p>No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@inject CatalogService CatalogService

<PageTitle>Course Details</PageTitle>

@if (course is not null)
{
    <h1>@course.Code — @course.Name</h1>

    <div class="card">
        <h2>Course Information</h2>
        <p><strong>Credits:</strong> @course.Credits</p>
        <p><strong>Schedule:</strong> @course.Schedule</p>
        <p><strong>Department:</strong> @CatalogService.GetDepartment(course.DepartmentId)?.Name</p>
        <p>@course.Description</p>
    </div>

    <div class="card">
        <h2>Instructor</h2>
        <p><strong>@course.InstructorName</strong></p>
        <p>@course.InstructorBio</p>
    </div>

    <p><a href="enroll" class="btn">Enroll in This Course →</a></p>
}
else
{
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
    <a href="courses">← Back to Courses</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject CatalogService CatalogService

<PageTitle>Enroll</PageTitle>

<h1>Enrollment Request</h1>

@if (Submitted)
{
    <div class="card success-message">
        <h2>Enrollment Request Submitted!</h2>
        <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for
            <strong>@CatalogService.GetCourse(Model.CourseId)?.Name</strong> has been received.</p>
        <p>Student ID: @Model.StudentId</p>
        <p>You will receive a confirmation email within 2–3 business days.</p>
        <a href="enroll">Submit Another Request</a>
    </div>
}
else
{
    <form method="post" @formname="enrollment">
        <AntiforgeryToken />
        <div class="form-group">
            <label for="name">Full Name</label>
            <input type="text" id="name" name="Model.Name" value="@Model.Name" required />
        </div>
        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required />
        </div>
        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="">— Select a course —</option>
                @foreach (var course in CatalogService.GetCourses(null, null))
                {
                    <option value="@course.Id">@course.Code — @course.Name</option>
                }
            </select>
        </div>
        <button type="submit" class="btn">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        if (!string.IsNullOrWhiteSpace(Model.Name) && !string.IsNullOrWhiteSpace(Model.StudentId) && Model.CourseId > 0)
        {
            Submitted = true;
        }
    }
}

